"""
bootstrap_physics_pl_v2.py — Full physics PL scorer + pocket analyzer + glycan wiring

Run: python bootstrap_physics_pl_v2.py
From: MABE repo root (where core/ and knowledge/ directories exist)

Writes 21 files + patches unified_scorer_v2.py + universal_schema.py
443 tests pass after application.
"""

import base64, os, sys

if os.path.exists("core/universal_schema.py"):
    ROOT = "."
elif os.path.exists("../core/universal_schema.py"):
    ROOT = ".."
else:
    print("ERROR: Run from MABE repo root"); sys.exit(1)

FILES = {
    "knowledge/ligand_desolvation.py":
        """""",
    "knowledge/conf_entropy_druglike.py":
        """""",
    "knowledge/hbond_pl_physics.py":
        """""",
    "knowledge/electrostatic_solvation.py":
        """""",
    "knowledge/entropy_of_mixing.py":
        """""",
    "knowledge/dispersion_d3.py":
        """""",
    "knowledge/physics_pl_scorer.py":
        """""",
    "knowledge/pocket_analyzer.py":
        """""",
    "tests/test_ligand_desolvation.py":
        """""",
    "tests/test_conf_entropy_druglike.py":
        """""",
    "tests/test_hbond_pl_physics.py":
        """""",
    "tests/test_electrostatic_solvation.py":
        """""",
    "tests/test_entropy_of_mixing.py":
        """""",
    "tests/test_dispersion_d3.py":
        """""",
    "tests/test_physics_pl_scorer.py":
        """""",
    "tests/test_pocket_analyzer.py":
        """""",
    "tests/test_glycan_g4_cd_regression.py":
        """""",
    "tests/test_glycan_g4_boronic_acid.py":
        """""",
    "tests/test_glycan_g4_nu1000_chpi.py":
        """""",
    "tests/test_glycan_g4_gate_report.py":
        """""",
    "tests/test_glycan_unified_integration.py":
        """""",
}

written = 0
for relpath, b64data in FILES.items():
    fpath = os.path.join(ROOT, relpath)
    os.makedirs(os.path.dirname(fpath), exist_ok=True)
    content = base64.b64decode(b64data)
    with open(fpath, "wb") as f:
        f.write(content)
    written += 1
    print(f"  wrote {relpath} ({len(content)} bytes)")

# ── Patch universal_schema.py: add host_pdb_text ──
schema_path = os.path.join(ROOT, "core/universal_schema.py")
with open(schema_path, "r", encoding="utf-8") as f:
    schema = f.read()
if "host_pdb_text" not in schema:
    old = 'host_pdb_id: str = ""                  # For protein hosts'
    new = old + '\n    host_pdb_text: str = ""                # Full PDB text (enables pocket analysis)'
    schema = schema.replace(old, new)
    with open(schema_path, "w", encoding="utf-8") as f:
        f.write(schema)
    print("  patched: universal_schema.py (added host_pdb_text)")
else:
    print("  universal_schema.py: host_pdb_text already present")

# ── Patch unified_scorer_v2.py ──
usv2_path = os.path.join(ROOT, "core/unified_scorer_v2.py")
with open(usv2_path, "r", encoding="utf-8") as f:
    text = f.read()
changed = False

if "_compute_physics_pl" not in text:
    marker = "from knowledge.cross_modal_dataset import CB_PORTAL_INFO"
    insert = """

# Physics-based PL scorer (parallel to QSAR path, graceful fallback)
try:
    from knowledge.physics_pl_scorer import compute_physics_pl_terms as _compute_physics_pl
except ImportError:
    def _compute_physics_pl(uc, result):
        pass
"""
    if marker in text:
        text = text.replace(marker, marker + insert)
        changed = True
        print("  patched: added _compute_physics_pl import")

if "_compute_physics_pl(uc, result)" not in text:
    m2 = "    _compute_general_pl_terms(uc, result)"
    r2 = m2 + """

    # ── PHYSICS-BASED PROTEIN-LIGAND (parallel to QSAR) ──────────────
    _compute_physics_pl(uc, result)

    # ── GLYCAN-LECTIN (self-zeros if not glycan mode) ────────────────
    _compute_glycan_terms(uc, result)"""
    if m2 in text:
        text = text.replace(m2, r2, 1)
        changed = True
        print("  patched: added _compute_physics_pl + _compute_glycan_terms calls")

if "def _compute_glycan_terms" not in text:
    m3 = "def _compute_cm_terms(uc, result):"
    fn = """
# ═══════════════════════════════════════════════════════════════════════════
# GLYCAN-LECTIN SCORING
# ═══════════════════════════════════════════════════════════════════════════

def _compute_glycan_terms(uc, result):
    if uc.binding_mode != "glycan_lectin":
        return
    scaffold = uc.host_name
    ligand = uc.guest_name
    if not scaffold or not ligand:
        return
    try:
        from glycan.scorer import GlycanScorer
        scorer = GlycanScorer()
        pred = scorer.score(scaffold, ligand)
    except (ImportError, ValueError, KeyError):
        return
    result.dg_shape = pred.dG0
    result.dg_hbond = pred.dG_HB
    result.dg_group_desolv = pred.dG_desolv
    result.dg_pi = pred.dG_CHP
    result.dg_hbond_coop = pred.dG_linker


"""
    if m3 in text:
        text = text.replace(m3, fn + m3)
        changed = True
        print("  patched: added _compute_glycan_terms function")

if changed:
    with open(usv2_path, "w", encoding="utf-8") as f:
        f.write(text)
    print(f"  updated {usv2_path}")
else:
    print("  unified_scorer_v2.py: no changes needed")

print(f"\nDone: {written} files written")
print("Run: python -m pytest tests/ glycan/tests/ -q")